{
  render: () => <div style={{
    display: "flex",
    flexDirection: "column",
    gap: "32px"
  }}>
      <div>
        <Title variant={TitleVariant.TITLE_4}>Branded Color (Default)</Title>
        <CheckboxTree title="Branded Tree" caption="Default branded color variant" checkboxesColor={CheckboxColor.BRANDED} items={basicItems} />
      </div>
      <div>
        <Title variant={TitleVariant.TITLE_4}>Neutral Color</Title>
        <CheckboxTree title="Neutral Tree" caption="Neutral color variant for subtle interfaces" checkboxesColor={CheckboxColor.NEUTRAL} items={basicItems} />
      </div>
    </div>,
  parameters: {
    docs: {
      description: {
        story: "Showcase of both color variations available for CheckboxTree."
      }
    }
  }
}
